,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select',
'    c.STORAGE_LOCATION_ID as STORAGE_LOCATION_ID',
'    , c.WAREHOUSE_ID as WAREHOUSE_ID',
'    , c.WAREHOUSE_AREA_ID as WAREHOUSE_AREA_ID',
