,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select',
'    c.RETURN_LINE_ID as RETURN_LINE_ID',
'    , c.RETURN_ID as RETURN_ID',
'    , c.LINE_NUMBER as LINE_NUMBER',
'    , c.ITEM_ID as ITEM_ID',
'    , c.INVENTORY_LOT_ID as INVENTORY_LOT_ID',
'    , c.EXPECTED_QUANTITY as EXPECTED_QUANTITY',
'    , c.RECEIVED_QUANTITY as RECEIVED_QUANTITY',
'    , c.RETURNED_CONDITION_CODE as RETURNED_CONDITION_CODE',
'    , c.REUSABLE_QUANTITY as REUSABLE_QUANTITY',
'    , c.QUARANTINE_QUANTITY as QUARANTINE_QUANTITY',
'    , c.DAMAGED_QUANTITY as DAMAGED_QUANTITY',
'    , c.WRITEOFF_QUANTITY as WRITEOFF_QUANTITY',
'    , c.DISPOSITION_CODE as DISPOSITION_CODE',
'from SCM_RETURN_LINES c',
'where',
'    c.RETURN_ID = to_number(:P63_RETURN_ID)',
'order by',
'    LINE_NUMBER asc'))
